use async_trait::async_trait;

#[async_trait]
trait MyTrait {
    async fn method(&self) -> String;
}

struct MyStruct;

#[async_trait]
impl MyTrait for MyStruct {
    async fn method(&self) -> String {
        String::from("hello")
    }
}

fn main() {}
